\[
\begin{equation*}
z(x, y)=\frac{1}{2}\left(a x^{2}+2 b x y+c y^{2}\right)+(\text { third-order and higher terms }) . \tag{A1}
\end{equation*}
\]

\[
\begin{equation*}
\frac{\partial z}{\partial x}=a x+b y+(\text { second-order and higher terms })=0, \tag{A2}
\end{equation*}
\]

\[
\begin{equation*}
z=\frac{1}{2} \frac{a c-b^{2}}{a} y^{2}=\frac{1}{2} K_{\mathrm{t}} y^{2} \tag{A3}
\end{equation*}
\]

\[
\begin{equation*}
K_{\mathrm{t}}=\frac{a c-b^{2}}{a} \tag{A4}
\end{equation*}
\]

\[
\begin{equation*}
z=\frac{1}{2} a x^{2}=\frac{1}{2} K_{\mathrm{r}} x^{2} \tag{A5}
\end{equation*}
\]

\[
\begin{equation*}
K_{\mathrm{r}}=a . \tag{A6}
\end{equation*}
\]

\[
\begin{equation*}
K_{\mathrm{r}} K_{\mathrm{t}}=a c-b^{2}=\frac{\left(\partial^{2} z / \partial x^{2}\right)\left(\partial^{2} z / \partial y^{2}\right)-\left(\partial^{2} z / \partial x \partial y\right)^{2}}{1+(\partial z / \partial x)^{2}+(\partial z / \partial y)^{2}}=K, \tag{A7}
\end{equation*}
\]
